30	        this.boa_token = boa_token
31	        this.audio_token = audio_token
32	        const audio_tokens_expanded = audio_token.repeat(this.audio_seq_length);
33	        this.full_audio_sequence = `\n\n${boa_token}${audio_tokens_expanded}${eoa_token}\n\n`
34	
35	        this.image_token_id = image_token_id
36	        this.boi_token = boi_token
