46	     * @param {RawAudio|RawAudio[]|RawAudio[][]} audio
47	     * @returns {Promise<any>}
48	     */
49	    async _call(text, images = null, audio = null, options = {}) {
50	
51	        if (typeof text === 'string') {
52	            text = [text];
53	        }
